in our mainactivity, we can make api call to retrieve flight information and display it in a recyclerview.

```
class mainactivity : appcompatactivity() {
    private lateinit var flightservice: flightservice
    private lateinit var flightadapter: flightadapter

    override fun oncreate(savedinstancestate: bundle?) {
        super.oncreate(savedinstancestate)
        setcontentview(r.layout.activity_main)

        flightservice = retrofit.builder()
            .baseurl("https://api.myapp.com/")
            .client(okhttpclient())
            .addconverterfactory(gsonconverterfactory.create())
            .build()
            .create(flightservice::class.java)

        flightadapter = flightadapter(listof())
        recyclerview.adapter = flightadapter
        recyclerview.layoutmanager = linearlayoutmanager(this)

        getflights()
    }

    private fun getflights() {
        flightservice.getflights().enqueue(object : callback<list<flight>> {
            override fun onresponse(call: call<list<flight>>, response: response<list<flight>>) {
                if (response.issuccessful) {
                    val flights = response.body()
                    flightadapter.update(flights ?: listof())
                } else {
                    // handle error
                }
            }

            override fun onfailure(call: call<list<flight>>, t: throwable) {
                // handle error
            }
        })
    }
}
```

our flightadapter can display flight information in a recyclerview item.

```
class flightadapter(private var flights: list<flight>) : recyclerview.adapter<flightadapter.viewholder>() {
    override fun oncreateviewholder(parent: viewgroup, viewtype: int): viewholder {
        val view = layoutinflater.from(parent.context).inflate(r.layout.item_flight, parent, false)
        return viewholder(view)
    }

    override fun onbindviewholder(holder: viewholder, position: int) {
        val flight = flights[position]
        holder.flightnumberview.text = flight.flightnumber
        holder.airlineview.text = flight.airline
        holder.departureview.text = flight.departuretime
        holder.arrivalview.text = flight.arrivaltime
        holder.updateview.text = flight.updates.jointostring("\n")
    }

    override fun getitemcount(): int {
        return flights.size
    }

    fun update(flights: list<flight>) {
        this.flights = flights
        notifydatasetchanged()
    }

    class viewholder(itemview: view) : recyclerview.viewholder(itemview) {
        val flightnumberview: textview = itemview.findviewbyid(r.id.flightnumber)
        val airlineview: textview = itemview.findviewbyid(r.id.airline)
        val departureview: textview = itemview.findviewbyid(r.id.departure)
        val arrivalview: textview = itemview.findviewbyid(r.id.arrival)
        val updateview: textview = itemview.findviewbyid(r.id.update)
    }
}
```

