func imagepickercontroller(_ picker: uiimagepickercontroller, didfinishpickingmediawithinfo info: [uiimagepickercontroller.infokey : any]) {
    let image = info[.editedimage] as! uiimage
    imageview.image = image
    dismiss(animated: true)
}
```

7. Create an instance of ```vnimagerequesthandler``` to process the image:

```swift
guard let image = imageview.image else { return }
let requesthandler = vnimagerequesthandler(cgimage: image.cgimage!, options: [:])
```

8. Create a request to detect objects and scenes in the photo:

```swift
let request = vnrecognizesceneandobjectsrequest(completionhandler: { (request, error) in
    guard let results = request.results as? [vnrecognizedobjectobservation] else { return }
    for result in results {
        print(result.labels.first!.identifier)
    }
})
```

9. Perform the request:

```swift
do {
    try requesthandler.perform([request])
} catch {
    print(error)
}
```

10. Run the app and select a photo to see the recognized objects and scenes in the console.

