    let mut size_of_array: usize = 0;

    // Run a loop until the user inputs a valid integer size
    loop {
        println!("Enter the size of the array: ");
        let mut input_value = String::new();
        io::stdin()
            .read_line(&mut input_value)
            .expect("Failed to read input");
        match input_value.trim().parse() {
            Ok(num) => {
                size_of_array = num;
                break;
            }
            Err(_) => {
                println!("Please enter a valid integer size.");
                continue;
            }
        };
    }

    let mut arr = [0; 10];

    // Run a loop to get array inputs from user
    for I in 0..size_of_array {
        loop {
            println!("Enter the array element at index {}: ", i);
            let mut input_value = String::new();
            io::stdin()
                .read_line(&mut input_value)
                .expect("Failed to read input");
            match input_value.trim().parse() {
                Ok(num) => {
                    arr[i] = num;
                    break;
                }
                Err(_) => {
                    println!("Please enter a valid numeric value.");
                    continue;
                }
            };
        }
    }

    let mut sum = 0;

    // Run a loop to calculate the sum of array elements
    for I in 0..size_of_array {
        sum += arr[i];
    }

    println!("The sum of the array elements is {}.", sum);
}

